.vbwd-page {
  /* Theme-aware port of the /plugins design system: colours follow the active
     theme (theme-switcher sets --color-*); vibrant indigo fallbacks otherwise. */
  --vbwd-accent: var(--color-accent, var(--color-primary, #2563eb));
  --vbwd-accent-dark: var(--color-accent-dark, var(--color-primary-dark, #1d4ed8));
  --vbwd-accent-soft: var(--color-accent-soft, color-mix(in srgb, var(--vbwd-accent) 14%, var(--vbwd-surface)));
  --vbwd-gradient: var(--color-gradient, linear-gradient(135deg, #1d4ed8 0%, #5b21b6 100%));
  --vbwd-text: var(--color-text, #0f172a);
  --vbwd-text-muted: var(--color-text-muted, #475569);
  --vbwd-surface: var(--color-surface, #ffffff);
  --vbwd-surface-soft: var(--color-surface-soft, color-mix(in srgb, var(--vbwd-text) 5%, var(--vbwd-surface)));
  --vbwd-border: var(--color-border, #e2e8f0);
  --vbwd-heading: var(--color-heading, var(--vbwd-text));
  --vbwd-radius: 14px;
  --vbwd-radius-lg: 22px;
  --vbwd-shadow-sm: 0 1px 2px rgba(15,23,42,0.06), 0 1px 3px rgba(15,23,42,0.08);
  --vbwd-shadow-md: 0 4px 6px -1px rgba(15,23,42,0.10), 0 2px 4px -2px rgba(15,23,42,0.08);
  --vbwd-code-bg: var(--color-code-bg, #0f172a);
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', system-ui, sans-serif;
  color: var(--vbwd-text);
  line-height: 1.7;
  font-size: 16.5px;
  -webkit-font-smoothing: antialiased;
  max-width: 1040px;
  margin: 0 auto;
  padding: 0 20px 80px;
}
/* Theme the reading surface so docs stay readable on light AND dark. */
body { background: var(--color-bg, #f5f5f5); }
.vbwd-page *, .vbwd-page *::before, .vbwd-page *::after { box-sizing: border-box; }
.vbwd-page h1, .vbwd-page h2, .vbwd-page h3, .vbwd-page h4 { color: var(--vbwd-heading); line-height: 1.2; letter-spacing: -0.02em; margin: 0 0 0.6em; font-weight: 700; }
.vbwd-page p { margin: 0 0 1em; }
.vbwd-page a { color: var(--color-link, var(--vbwd-content-link, var(--vbwd-accent))); text-decoration: none; font-weight: 600; }
.vbwd-page a:hover { color: var(--color-link-hover, var(--vbwd-content-link-hover, var(--vbwd-accent))); text-decoration: underline; text-underline-offset: 3px; }

/* The page now uses the content-page layout (header / breadcrumb / footer
   layers, same as /plugins), so hide the legacy inline breadcrumb + footer-nav
   baked into the doc markup — the layout owns that chrome. */
.vbwd-page .vbwd-breadcrumb { display: none; }

/* ── Hero ─────────────────────────────────────────────────────────── */
.vbwd-page .vbwd-hero { background: var(--vbwd-gradient); color: var(--vbwd-hero-text, #fff); padding: clamp(3rem, 6vw, 4.5rem) clamp(1.5rem, 4vw, 3rem); text-align: center; position: relative; overflow: hidden; border-radius: var(--vbwd-radius-lg); margin: 18px 0 2.5rem; box-shadow: var(--vbwd-shadow-md); }
.vbwd-page .vbwd-hero::before { content: ""; position: absolute; inset: 0; background: radial-gradient(circle at 20% 10%, rgba(255,255,255,0.25), transparent 40%), radial-gradient(circle at 80% 90%, rgba(255,255,255,0.18), transparent 45%); pointer-events: none; }
.vbwd-page .vbwd-hero > * { position: relative; }
.vbwd-page .vbwd-hero__eyebrow { display: inline-block; padding: 0.35rem 0.9rem; border-radius: 999px; background: rgba(255,255,255,0.18); color: var(--vbwd-hero-text, #fff); font-size: 0.78rem; font-weight: 600; letter-spacing: 0.1em; text-transform: uppercase; margin-bottom: 1.1rem; backdrop-filter: blur(4px); }
.vbwd-page .vbwd-hero h1 { color: var(--vbwd-hero-text, #fff); font-size: clamp(2rem, 4vw, 2.9rem); font-weight: 800; margin: 0 0 0.6rem; text-shadow: 0 2px 8px rgba(0,0,0,0.18); }
.vbwd-page .vbwd-hero__lead { color: rgba(255,255,255,0.95); font-size: clamp(1.02rem, 1.6vw, 1.2rem); max-width: 660px; margin: 0 auto; }

/* ── Sections ─────────────────────────────────────────────────────── */
.vbwd-page .vbwd-section { padding: 2.25rem 0; }
.vbwd-page .vbwd-section + .vbwd-section { border-top: 1px solid var(--vbwd-border); }
.vbwd-page .vbwd-section h2 { font-size: clamp(1.4rem, 2.4vw, 1.85rem); margin: 0 0 0.7rem; }
.vbwd-page .vbwd-section h3 { font-size: 1.15rem; margin: 1.4rem 0 0.5rem; }
.vbwd-page .vbwd-section ul, .vbwd-page .vbwd-section ol { margin: 0 0 1em; padding-left: 1.4rem; }
.vbwd-page .vbwd-section li { margin: 0.35rem 0; }

/* ── Inline code + code blocks ────────────────────────────────────── */
.vbwd-page code { font-family: 'JetBrains Mono', ui-monospace, SFMono-Regular, Menlo, monospace; background: var(--vbwd-accent-soft); color: var(--vbwd-accent); padding: 0.15em 0.45em; border-radius: 6px; font-size: 0.88em; font-weight: 500; }
/* !important: the canonical CMS theme scopes `.cms-page__body[data-v] pre`
   with an attribute selector (higher specificity) and forces a light surface,
   which left our light code text invisible. Force the dark code block. */
.vbwd-page pre { background: var(--vbwd-code-bg) !important; color: var(--vbwd-code-text, #e2e8f0) !important; border-radius: var(--vbwd-radius); padding: 18px 20px; overflow-x: auto; margin: 0 0 1em; font-size: 0.85rem; line-height: 1.6; box-shadow: var(--vbwd-shadow-sm); }
.vbwd-page pre code { background: none !important; color: var(--vbwd-code-text, #e2e8f0) !important; padding: 0; font-weight: 400; }

/* ── Callout ──────────────────────────────────────────────────────── */
.vbwd-page .vbwd-callout { background: var(--vbwd-accent-soft); border-left: 4px solid var(--vbwd-accent); border-radius: var(--vbwd-radius); padding: 1.1rem 1.35rem; margin: 0 0 1.25rem; color: var(--vbwd-text); }
.vbwd-page .vbwd-callout strong { color: var(--vbwd-accent); }

/* ── Tables ───────────────────────────────────────────────────────── */
.vbwd-page table { width: 100%; border-collapse: separate; border-spacing: 0; margin: 1rem 0 1.25rem; font-size: 0.94rem; background: var(--vbwd-surface); border: 1px solid var(--vbwd-border); border-radius: var(--vbwd-radius); overflow: hidden; box-shadow: var(--vbwd-shadow-sm); }
.vbwd-page th { text-align: left; padding: 0.8rem 1rem; background: var(--vbwd-surface-soft); color: var(--vbwd-text-muted); font-size: 0.76rem; font-weight: 700; letter-spacing: 0.08em; text-transform: uppercase; border-bottom: 1px solid var(--vbwd-border); }
.vbwd-page td { padding: 0.8rem 1rem; border-bottom: 1px solid var(--vbwd-border); vertical-align: top; }
.vbwd-page tr:last-child td { border-bottom: none; }
.vbwd-page tbody tr:hover td { background: var(--vbwd-accent-soft); }

/* ── Card grid ────────────────────────────────────────────────────── */
.vbwd-page .vbwd-cards { display: grid; grid-template-columns: repeat(auto-fit, minmax(260px, 1fr)); gap: 1rem; margin: 1.25rem 0 0; }
.vbwd-page .vbwd-card { background: var(--vbwd-surface); border: 1px solid var(--vbwd-border); border-radius: var(--vbwd-radius); padding: 1.25rem 1.35rem; box-shadow: var(--vbwd-shadow-sm); transition: transform 0.15s ease, box-shadow 0.15s ease, border-color 0.15s ease; position: relative; overflow: hidden; text-decoration: none; color: inherit; display: block; }
.vbwd-page .vbwd-card::before { content: ""; position: absolute; left: 0; top: 0; bottom: 0; width: 3px; background: var(--vbwd-accent); opacity: 0.7; }
.vbwd-page .vbwd-card:hover { transform: translateY(-2px); box-shadow: var(--vbwd-shadow-md); border-color: var(--vbwd-accent); }
.vbwd-page .vbwd-card__num { font-size: 0.72rem; font-weight: 700; color: var(--vbwd-accent); letter-spacing: 0.08em; }
.vbwd-page .vbwd-card h3 { margin: 0 0 0.3rem; font-size: 1.02rem; font-weight: 700; color: var(--vbwd-text); }
.vbwd-page .vbwd-card p { margin: 0; font-size: 0.92rem; color: var(--vbwd-text-muted); line-height: 1.55; }

/* ── Pills / footer nav ───────────────────────────────────────────── */
.vbwd-page .vbwd-pill { display: inline-block; font-size: 0.74rem; font-weight: 700; padding: 0.25rem 0.7rem; border-radius: 999px; background: var(--vbwd-accent-soft); color: var(--vbwd-accent); letter-spacing: 0.04em; margin: 0 6px 6px 0; }
.vbwd-page .vbwd-footer-nav { margin-top: 2.5rem; padding-top: 1.4rem; border-top: 1px solid var(--vbwd-border); font-size: 0.9rem; color: var(--vbwd-text-muted); }
.vbwd-page .vbwd-footer-nav a { color: var(--vbwd-accent); font-weight: 600; }
.vbwd-page .vbwd-shot { margin: 1.75rem 0 0.5rem; border: 1px solid var(--vbwd-border); border-radius: var(--vbwd-radius); overflow: hidden; box-shadow: var(--vbwd-shadow-md); background: var(--vbwd-surface); }
.vbwd-page .vbwd-shot img { display: block; width: 100%; height: auto; }
.vbwd-page .vbwd-shot figcaption { padding: 0.55rem 0.9rem; font-size: 0.8rem; color: var(--vbwd-text-muted); background: var(--vbwd-surface-soft); border-top: 1px solid var(--vbwd-border); }
/* Portrait phone screenshot gallery: a responsive row of capped-width shots. */
.vbwd-page .vbwd-shots--phones { display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 1.25rem; margin: 1.75rem 0 0.5rem; align-items: start; }
.vbwd-page .vbwd-shot--phone { margin: 0; max-width: 320px; }
.vbwd-page .vbwd-shot--phone img { background: var(--vbwd-surface-soft); }
@media (max-width: 520px) { .vbwd-page .vbwd-shots--phones { grid-template-columns: 1fr 1fr; gap: 0.75rem; } }
.vbwd-page .ok { color: var(--color-success, #16a34a); font-weight: 600; }

/* ── Table of contents (the /docs hub) ────────────────────────────── */
.vbwd-page .vbwd-toc { display: grid; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); gap: 1.25rem 2rem; margin: 1.25rem 0 0; }
.vbwd-page .vbwd-toc__group h3 { font-size: 0.74rem; font-weight: 700; text-transform: uppercase; letter-spacing: 0.08em; color: var(--vbwd-text-muted); margin: 0 0 0.6rem; padding-bottom: 0.45rem; border-bottom: 1px solid var(--vbwd-border); }
.vbwd-page .vbwd-toc__group ul { list-style: none; margin: 0; padding: 0; }
.vbwd-page .vbwd-toc__group li { margin: 0.3rem 0; line-height: 1.4; }
.vbwd-page .vbwd-toc__group a { font-weight: 500; }
.vbwd-page .vbwd-toc__group a:hover { text-decoration: underline; text-underline-offset: 3px; }

/* ── Layout chrome geometry (match /plugins): centre the header / footer /
   breadcrumb on the same column as the page. No colours/borders. ──── */
.cms-layout .cms-widget--header-nav,
.cms-layout .cms-widget--footer-nav,
.cms-layout .cms-area--vue .cms-breadcrumb { max-width: 1100px; margin-left: auto; margin-right: auto; }
.cms-layout .cms-area--vue .cms-breadcrumb { padding-left: 16px; }

/* ── Responsive ───────────────────────────────────────────────────── */
@media (max-width: 640px) {
  .vbwd-page { font-size: 16px; }
  .vbwd-page .vbwd-hero { margin: 12px 0 2rem; padding: 2.5rem 1.1rem; }
  .vbwd-page .vbwd-cards { grid-template-columns: 1fr; }
}
